var LocalStorageRepository = class {
  constructor(name) {
    this.name = name;
  }
  /**
   * Save data to local storage. If data with the same key exists, it will be merged.
   * @param data
   */
  save(address, data) {
    this.run(() => {
      let all3 = this.getAll(address);
      all3 = { [address]: { ...all3, ...data } };
      localStorage.setItem(this.name, JSON.stringify(all3));
    });
  }
  /**
   * get data from local storage
   * @param key
   * @returns
   */
  get(address, key) {
    const data = this.getAll(address);
    if (!data) {
      return null;
    }
    return data[key];
  }
  /**
   * get all data from local storage
   * @param address
   * @returns
   */
  getAll(address) {
    try {
      const data = localStorage.getItem(this.name);
      if (!data) {
        return null;
      }
      return JSON.parse(data)[address];
    } catch (error) {
      console.error(error);
      return null;
    }
  }
  clear(address) {
    this.run(() => {
      const all3 = this.getAll(address);
      if (!all3) {
        return;
      }
      delete all3[address];
      localStorage.setItem(this.name, JSON.stringify(all3));
    });
  }
  update(address, key, data) {
    this.run(() => {
      const all3 = this.getAll(address);
      all3[key] = data;
      localStorage.setItem(this.name, JSON.stringify(all3));
    });
  }
  remove(address, key) {
    this.run(() => {
      const all3 = this.getAll(address);
      delete all3[key];
      localStorage.setItem(this.name, JSON.stringify(all3));
    });
  }
  run(cb) {
    if (typeof window !== "undefined" && typeof localStorage !== "undefined") {
      cb();
    }
  }
};
